/**
 * Authentication material, tagged by protocol. UUIDs are passed as
 * lowercase 36-char strings.
 */
sealed class FfiAuth {
    
    data class Vless(
        val `uuid`: kotlin.String, 
        val `flow`: kotlin.String?, 
        val `encryption`: kotlin.String?) : FfiAuth()
        
    {
        

        companion object
    }
    
    data class Vmess(
        val `uuid`: kotlin.String, 
        val `alterId`: kotlin.UShort, 
        val `security`: kotlin.String?) : FfiAuth()
        
    {
        

        companion object
    }
    
    data class Trojan(
        val `password`: kotlin.String) : FfiAuth()
        
    {
        

        companion object
    }
    
    data class Shadowsocks(
        val `method`: kotlin.String, 
        val `password`: kotlin.String) : FfiAuth()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeFfiAuth : FfiConverterRustBuffer<FfiAuth>{
    override fun read(buf: ByteBuffer): FfiAuth {
        return when(buf.getInt()) {
            1 -> FfiAuth.Vless(
                FfiConverterString.read(buf),
                FfiConverterOptionalString.read(buf),
                FfiConverterOptionalString.read(buf),
                )
            2 -> FfiAuth.Vmess(
                FfiConverterString.read(buf),
                FfiConverterUShort.read(buf),
                FfiConverterOptionalString.read(buf),
                )
            3 -> FfiAuth.Trojan(
                FfiConverterString.read(buf),
                )
            4 -> FfiAuth.Shadowsocks(
                FfiConverterString.read(buf),
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: FfiAuth) = when(value) {
        is FfiAuth.Vless -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`uuid`)
                + FfiConverterOptionalString.allocationSize(value.`flow`)
                + FfiConverterOptionalString.allocationSize(value.`encryption`)
            )
        }
        is FfiAuth.Vmess -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`uuid`)
                + FfiConverterUShort.allocationSize(value.`alterId`)
                + FfiConverterOptionalString.allocationSize(value.`security`)
            )
        }
        is FfiAuth.Trojan -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`password`)
            )
        }
        is FfiAuth.Shadowsocks -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.`method`)
                + FfiConverterString.allocationSize(value.`password`)
            )
        }
    }

    override fun write(value: FfiAuth, buf: ByteBuffer) {
        when(value) {
            is FfiAuth.Vless -> {
                buf.putInt(1)
                FfiConverterString.write(value.`uuid`, buf)
                FfiConverterOptionalString.write(value.`flow`, buf)
                FfiConverterOptionalString.write(value.`encryption`, buf)
                Unit
            }
            is FfiAuth.Vmess -> {
                buf.putInt(2)
                FfiConverterString.write(value.`uuid`, buf)
                FfiConverterUShort.write(value.`alterId`, buf)
                FfiConverterOptionalString.write(value.`security`, buf)
                Unit
            }
            is FfiAuth.Trojan -> {
                buf.putInt(3)
                FfiConverterString.write(value.`password`, buf)
                Unit
            }
            is FfiAuth.Shadowsocks -> {
                buf.putInt(4)
                FfiConverterString.write(value.`method`, buf)
                FfiConverterString.write(value.`password`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }
}





