/**
 * Error variants returned across the FFI boundary.
 *
 * Every variant carries a textual `message` so the platform side can
 * surface the precise reason without reaching into the enum shape.
 */
sealed class GmvpnException(message: String): kotlin.Exception(message) {
        
        class InvalidUri(message: String) : GmvpnException(message)
        
        class UnsupportedProtocol(message: String) : GmvpnException(message)
        
        class MissingField(message: String) : GmvpnException(message)
        
        class InvalidValue(message: String) : GmvpnException(message)
        
        class Decode(message: String) : GmvpnException(message)
        
        class Serialization(message: String) : GmvpnException(message)
        

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<GmvpnException> {
        override fun lift(error_buf: RustBuffer.ByValue): GmvpnException = FfiConverterTypeGmvpnError.lift(error_buf)
    }
}

/**
 * @suppress
 */
public object FfiConverterTypeGmvpnError : FfiConverterRustBuffer<GmvpnException> {
    override fun read(buf: ByteBuffer): GmvpnException {
        
            return when(buf.getInt()) {
            1 -> GmvpnException.InvalidUri(FfiConverterString.read(buf))
            2 -> GmvpnException.UnsupportedProtocol(FfiConverterString.read(buf))
            3 -> GmvpnException.MissingField(FfiConverterString.read(buf))
            4 -> GmvpnException.InvalidValue(FfiConverterString.read(buf))
            5 -> GmvpnException.Decode(FfiConverterString.read(buf))
            6 -> GmvpnException.Serialization(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: GmvpnException): ULong {
        return 4UL
    }

    override fun write(value: GmvpnException, buf: ByteBuffer) {
        when(value) {
            is GmvpnException.InvalidUri -> {
                buf.putInt(1)
                Unit
            }
            is GmvpnException.UnsupportedProtocol -> {
                buf.putInt(2)
                Unit
            }
            is GmvpnException.MissingField -> {
                buf.putInt(3)
                Unit
            }
            is GmvpnException.InvalidValue -> {
                buf.putInt(4)
                Unit
            }
            is GmvpnException.Decode -> {
                buf.putInt(5)
                Unit
            }
            is GmvpnException.Serialization -> {
                buf.putInt(6)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




